#include <cuda.h>
#include <cuda_runtime.h>
#include <math.h>
#include <stdio.h>
#include <vector>
#include <string.h>
#include <stdlib.h>
#include <float.h>
#include <iostream>
#include <sys/time.h>

#define REC_LENGTH 49

typedef struct latLong
{
    float lat;
    float lng;
} LatLong;

typedef struct record
{
    char recString[REC_LENGTH];
    float distance;
} Record;

__global__ void NearestNeighbor(const LatLong* d_locations,
                                float* d_distances,
                                int numRecords,
                                float lat,
                                float lng) {
    int v_3 = blockIdx.x * blockDim.x + threadIdx.x;

    if (v_3 < numRecords) {
        const LatLong& latLong = d_locations[v_3];
        d_distances[v_3] = sqrtf((lat - latLong.lat) * (lat - latLong.lat) + (lng - latLong.lng) * (lng - latLong.lng));
    }
}

float *CudaFindNearestNeighbors(int numRecords,
                                std::vector<LatLong> &locations,
                                float lat,
                                float lng,
                                int timing);

int loadData(char *filename, std::vector<Record> &records, std::vector<LatLong> &locations);
void findLowest(std::vector<Record> &records, float *distances, int numRecords, int topN);
int parseCommandline(int argc, char *argv[], char* filename, int *r, float *lat, float *lng,
                     int *q, int *t, int *p, int *d);
void printUsage();

int main(int argc, char *argv[]) {
    std::vector<Record> records;
    float *recordDistances;

    std::vector<LatLong> locations;
    int i;

    char filename[100];
    int resultsCount = 10, quiet = 0, timing = 0, platform = -1, device = -1;
    float lat = 0.0f, lng = 0.0f;

    if (parseCommandline(argc, argv, filename, &resultsCount, &lat, &lng,
                         &quiet, &timing, &platform, &device)) {
        printUsage();
        return 0;
    }

    int numRecords = loadData(filename, records, locations);

    if (!quiet) {
        printf("Number of records: %d\n", numRecords);
        printf("Finding the %d closest neighbors.\n", resultsCount);
    }

    if (numRecords < resultsCount) resultsCount = numRecords;

    recordDistances = CudaFindNearestNeighbors(numRecords, locations, lat, lng, timing);

    findLowest(records, recordDistances, numRecords, resultsCount);

    if (!quiet) {
        for (i = 0; i < resultsCount; i++) {
            printf("%s --> Distance=%f\n", records[i].recString, records[i].distance);
        }
    }
    free(recordDistances);
    return 0;
}

float *CudaFindNearestNeighbors(int numRecords,
                                std::vector<LatLong> &locations,
                                float lat,
                                float lng,
                                int timing) {
    LatLong* d_locations = nullptr;
    float* d_distances = nullptr;
    float* distances = (float*)malloc(sizeof(float) * numRecords);
    if (!distances) {
        fprintf(stderr, "Failed to allocate host memory for distances\n");
        exit(1);
    }

    cudaError_t err;

    err = cudaMalloc((void**)&d_locations, sizeof(LatLong) * numRecords);
    if (err != cudaSuccess) {
        fprintf(stderr, "cudaMalloc d_locations failed: %s\n", cudaGetErrorString(err));
        exit(1);
    }

    err = cudaMalloc((void**)&d_distances, sizeof(float) * numRecords);
    if (err != cudaSuccess) {
        fprintf(stderr, "cudaMalloc d_distances failed: %s\n", cudaGetErrorString(err));
        cudaFree(d_locations);
        exit(1);
    }

    err = cudaMemcpy(d_locations, locations.data(), sizeof(LatLong) * numRecords, cudaMemcpyHostToDevice);
    if (err != cudaSuccess) {
        fprintf(stderr, "cudaMemcpy to d_locations failed: %s\n", cudaGetErrorString(err));
        cudaFree(d_locations);
        cudaFree(d_distances);
        exit(1);
    }

    int blockSize = 64;
    int gridSize = (numRecords + blockSize - 1) / blockSize;

    cudaEvent_t startEvent, stopEvent;
    float elapsedTime = 0.0f;
    if (timing) {
        cudaEventCreate(&startEvent);
        cudaEventCreate(&stopEvent);
        cudaEventRecord(startEvent, 0);
    }

    NearestNeighbor<<<gridSize, blockSize>>>(d_locations, d_distances, numRecords, lat, lng);

    err = cudaGetLastError();
    if (err != cudaSuccess) {
        fprintf(stderr, "Kernel launch failed: %s\n", cudaGetErrorString(err));
        cudaFree(d_locations);
        cudaFree(d_distances);
        free(distances);
        exit(1);
    }

    if (timing) {
        cudaEventRecord(stopEvent, 0);
        cudaEventSynchronize(stopEvent);
        cudaEventElapsedTime(&elapsedTime, startEvent, stopEvent);
        printf("Kernel execution time: %f ms\n", elapsedTime);
        cudaEventDestroy(startEvent);
        cudaEventDestroy(stopEvent);
    }

    err = cudaMemcpy(distances, d_distances, sizeof(float) * numRecords, cudaMemcpyDeviceToHost);
    if (err != cudaSuccess) {
        fprintf(stderr, "cudaMemcpy to host failed: %s\n", cudaGetErrorString(err));
        cudaFree(d_locations);
        cudaFree(d_distances);
        free(distances);
        exit(1);
    }

    cudaFree(d_locations);
    cudaFree(d_distances);

    return distances;
}

int loadData(char *filename, std::vector<Record> &records, std::vector<LatLong> &locations) {
    FILE *flist, *fp;
    int i = 0;
    char dbname[64], db_fullname[128];
    int recNum = 0;

    // data_folder is expected to be set externally or default to current directory
    extern char *data_folder;
    if (!data_folder) {
        data_folder = (char*)"."; // default to current directory
    }

    flist = fopen(filename, "r");
    if (!flist) {
        fprintf(stderr, "Error opening file list: %s\n", filename);
        exit(1);
    }
    while (fscanf(flist, "%63s\n", dbname) == 1) {
        snprintf(db_fullname, sizeof(db_fullname), "%s/%s", data_folder, dbname);
        fp = fopen(db_fullname, "r");
        if (!fp) {
            printf("error opening a db (%s)\n", db_fullname);
            exit(1);
        }

        while (true) {
            Record record;
            LatLong latLong;
            if (!fgets(record.recString, REC_LENGTH, fp)) break;
            int c = fgetc(fp); // consume newline or other char
            if (feof(fp)) break;

            char substr[6];

            for (i = 0; i < 5; i++) substr[i] = record.recString[i + 28];
            substr[5] = '\0';
            latLong.lat = atof(substr);

            for (i = 0; i < 5; i++) substr[i] = record.recString[i + 33];
            substr[5] = '\0';
            latLong.lng = atof(substr);

            locations.push_back(latLong);
            records.push_back(record);
            recNum++;
        }
        fclose(fp);
    }
    fclose(flist);
    return recNum;
}

void findLowest(std::vector<Record> &records, float *distances, int numRecords, int topN) {
    int i, j;
    float val;
    int minLoc;
    Record tempRec;
    float tempDist;

    for (i = 0; i < topN; i++) {
        minLoc = i;
        for (j = i; j < numRecords; j++) {
            val = distances[j];
            if (val < distances[minLoc]) minLoc = j;
        }

        tempRec = records[i];
        records[i] = records[minLoc];
        records[minLoc] = tempRec;

        tempDist = distances[i];
        distances[i] = distances[minLoc];
        distances[minLoc] = tempDist;

        records[i].distance = distances[i];
    }
}

int parseCommandline(int argc, char *argv[], char* filename, int *r, float *lat, float *lng,
                     int *q, int *t, int *p, int *d) {
    int i;
    if (argc < 2) return 1;
    strncpy(filename, argv[1], 100);
    char flag;

    for (i = 1; i < argc; i++) {
        if (argv[i][0] == '-') {
            flag = argv[i][1];
            switch (flag) {
                case 'r':
                    i++;
                    if (i < argc) *r = atoi(argv[i]);
                    break;
                case 'l':
                    if (argv[i][2] == 'a') {
                        i++;
                        if (i < argc) *lat = atof(argv[i]);
                    } else {
                        i++;
                        if (i < argc) *lng = atof(argv[i]);
                    }
                    break;
                case 'h':
                    return 1;
                case 'q':
                    *q = 1;
                    break;
                case 't':
                    *t = 1;
                    break;
                case 'p':
                    i++;
                    if (i < argc) *p = atoi(argv[i]);
                    break;
                case 'd':
                    i++;
                    if (i < argc) *d = atoi(argv[i]);
                    break;
                case 'f':
                    i++;
                    if (i < argc) {
                        extern char *data_folder;
                        data_folder = argv[i];
                    }
                    break;
            }
        }
    }
    if ((*d >= 0 && *p < 0) || (*p >= 0 && *d < 0))
        return 1;
    return 0;
}

